          const statusContentWrapper = document.getElementById("statusContentWrapper");
          const statusContent = document.getElementById("statusContent");
          const themeButtons = document.querySelectorAll(".theme-btn");

          const resistanceValue = _.get(
            all_variables,
            "stat_data.许婉如.抵抗值",
            null
          );

          function getResistanceStage(value) {
              if (value === null || value === undefined || value === "--") return "";
              const numValue = parseFloat(value);
              if (isNaN(numValue)) return "";

              if (numValue >= 105 && numValue <= 120) return "初始抗拒";
              if (numValue >= 90 && numValue <= 104) return "动摇妥协";
