              if (numValue >= 0 && numValue <= 19) return "献媚本性";
              return "";
          }
          const resistanceStage = getResistanceStage(resistanceValue);
          const resistanceDisplay = resistanceValue !== null ? resistanceValue : "--";

          document.getElementById("resistance-value").textContent = resistanceDisplay;

          const resistanceStageElem = document.getElementById("resistance-stage");
          if (resistanceStageElem && resistanceStage) {
            resistanceStageElem.textContent = resistanceStage;
            resistanceStageElem.style.display = "inline";
          } else if (resistanceStageElem) {
            resistanceStageElem.style.display = "none";
          }

          document.getElementById("current-thought").textContent = _.get(
