          );

          function applyTheme(theme) {
            container.setAttribute("data-theme", theme);
            themeButtons.forEach((btn) => {
              btn.classList.toggle("active", btn.dataset.theme === theme);
            });
            localStorage.setItem("xuwanru-status-theme", theme);
          }

          const savedTheme =
            localStorage.getItem("xuwanru-status-theme") || "paper";
          applyTheme(savedTheme);

          themeButtons.forEach((btn) => {
            btn.addEventListener("click", (e) => {
              e.stopPropagation();
              applyTheme(btn.dataset.theme);
            });
          });

          let isExpanded = true;
          const savedState = localStorage.getItem("xuwanru-status-expanded");
          if (savedState !== null) {
            isExpanded = savedState === "true";
          }

          function updateHeight() {
            if (isExpanded) {
              const contentHeight = statusContent.scrollHeight;
              statusContentWrapper.style.height = contentHeight + "px";
              statusWrapper.classList.remove("collapsed");
            } else {
              statusContentWrapper.style.height = "0px";
              statusWrapper.classList.add("collapsed");
