            updateHeight();
            localStorage.setItem("xuwanru-status-expanded", isExpanded.toString());
          }

          statusHeader.addEventListener("click", (e) => {
            if (!e.target.closest(".theme-btn")) {
              toggleExpand();
            }
          });

          setTimeout(() => {
            updateHeight();
          }, 50);

          window.addEventListener("resize", () => {
            if (isExpanded) {
              updateHeight();
            }
          });

          const resizeObserver = new ResizeObserver(() => {
            if (isExpanded) {
              updateHeight();
            }
          });
          resizeObserver.observe(statusContent);

        } catch (error) {
          console.error("渲染许婉如状态栏时出错:", error);
        }
