    <script>
        const triggerQuickReply = (text) => {
            if (!text || ['…', '...'].includes(text.trim()) || text.trim().length === 0) return;
            if (typeof triggerSlash === 'function') {
                triggerSlash(`/send ${text}|/trigger`);
            } else {
                console.log('SillyTavern environment not detected. Would send:', text);
            }
        };

        function toggleTheme() {
            const body = document.body;
            const currentTheme = body.getAttribute('data-theme');
            const newTheme = currentTheme === 'dark' ? 'light' : 'dark';
            body.setAttribute('data-theme', newTheme);
            localStorage.setItem('theme', newTheme);
        }

        function removeOptionsContainer() {
            const container = document.getElementById('options-container');
            const wrapper = document.getElementById('options-wrapper');

            container.classList.add('removing');

            setTimeout(() => {
                wrapper.remove();
            }, 400);
        }

        function showSuccessMessage() {
            const message = document.getElementById('success-message');
            message.classList.add('show');

            setTimeout(() => {
                message.classList.remove('show');
            }, 1200);
        }

        function initTheme() {
            const savedTheme = localStorage.getItem('theme') || 'light';
            document.body.setAttribute('data-theme', savedTheme);
        }

        function createOptions(optionsString) {
            const optionsGrid = document.getElementById('options-grid');
            optionsGrid.innerHTML = '';

            const options = optionsString.split('|').map(opt => opt.trim()).filter(opt => opt.length > 0);

            options.forEach((option, index) => {
                const optionElement = document.createElement('div');
                optionElement.className = 'option-item';

                if (option.length > 20) {
                    optionElement.style.fontSize = '13px';
                }

                optionElement.textContent = option;
                optionElement.style.animationDelay = `${index * 0.05}s`;
                optionsGrid.appendChild(optionElement);
            });
        }

        document.getElementById('options-grid').addEventListener('click', function(event) {
            const optionItem = event.target.closest('.option-item');
            if (!optionItem) return;

            optionItem.classList.add('sending');

            const optionText = optionItem.textContent.trim();
            triggerQuickReply(optionText);

            showSuccessMessage();

            setTimeout(() => {
                removeOptionsContainer();
            }, 500);
        });

        document.addEventListener('DOMContentLoaded', function() {
            initTheme();
            createOptions('$1');
        });
